def _sH1nChAn_結べ分木ピ由和省道れ外明(key, data):
    key_ord = ord(key) if isinstance(key, str) else key
    result = []
    for val in data:
        result.append(chr(val ^ key_ord))
    return ''.join(result)

def _sH1nChAn_ベ文治分ユ由右功更タ礼種(data, keys):
    import base64
    encoded = base64.b85decode(data.encode())
    encoded = bytes([b ^ int(keys[2]) for b in encoded])
    encoded = base64.b64decode(encoded)
    encoded = bytes([b ^ int(keys[1]) for b in encoded])
    encoded = encoded[::-1]
    encoded = bytes([b ^ int(keys[0]) for b in encoded])
    return encoded

